import { readFile, writeFile } from 'node:fs/promises';
import { dirname, join } from 'node:path';
import { fileURLToPath } from 'node:url';

const root = dirname(dirname(fileURLToPath(import.meta.url)));

const styleFragments = [
  'frontend/css/style/00-foundation.css',
  'frontend/css/style/10-components.css',
  'frontend/css/style/20-responsive.css',
  'frontend/css/style/30-palette-layout-refinement.css',
  'frontend/css/style/40-dashboard-provider-lists.css',
  'frontend/css/style/50-forms-and-utility-pages.css',
  'frontend/css/style/60-settings-guide-responsive.css',
];

const banner = '/* Generated by scripts/build-style-bundle.mjs. Edit frontend/css/style/*.css instead. */\n';

async function readFragment(path) {
  return readFile(join(root, path), 'utf8');
}

export async function buildStyleBundle({ check = false } = {}) {
  const body = (await Promise.all(styleFragments.map(readFragment)))
    .map((source) => source.trimEnd())
    .join('\n\n');
  const generated = `${banner}${body}\n`;
  const targetPath = join(root, 'frontend/css/style.css');

  if (check) {
    const current = await readFile(targetPath, 'utf8');
    if (current !== generated) {
      throw new Error('frontend/css/style.css is out of date. Run pnpm build to regenerate it from frontend/css/style/*.css.');
    }
    return generated;
  }

  await writeFile(targetPath, generated);
  return generated;
}

if (import.meta.url === `file://${process.argv[1]}`) {
  await buildStyleBundle({ check: process.argv.includes('--check') });
}
